import { useMutation, UseMutationOptions } from '@tanstack/react-query'

import { client, gql } from '../client'

export interface ImpresoraEliminarVariables {
  id: string
}

export const IMPRESORAELIMINAR = gql`
  mutation ImpresoraEliminar($id: ID!) {
    impresoraEliminar(id: $id)
  }
`

export const useImpresoraEliminar = (
  options?: UseMutationOptions<boolean, Error, ImpresoraEliminarVariables>,
) => {
  return useMutation<boolean, Error, ImpresoraEliminarVariables>({
    mutationFn: async (variables) => {
      const response = await client.request<{ impresoraEliminar: boolean }>(IMPRESORAELIMINAR, variables)
      return response.impresoraEliminar
    },
    ...options,
  })
}
